CREATE TABLE IF NOT EXISTS pmo_meeting_reminders (reminder_id BIGSERIAL PRIMARY KEY, meeting_id UUID, reminder_type TEXT NOT NULL, scheduled_at TIMESTAMPTZ NOT NULL, status TEXT NOT NULL DEFAULT 'pending', payload JSONB NOT NULL DEFAULT '{}'::jsonb, queued_at TIMESTAMPTZ, sent_at TIMESTAMPTZ, last_error TEXT, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
