const rows = typeof $json.reminders === 'string' ? JSON.parse($json.reminders || '[]') : ($json.reminders || []);
const fmt = (v) => v ? new Date(v).toLocaleString('es-EC', { timeZone: 'America/Guayaquil', dateStyle: 'medium', timeStyle: 'short' }) : '-';
return rows.map((r) => {
  const invitees = Array.isArray(r.invitees) ? r.invitees : (typeof r.invitees === 'string' ? JSON.parse(r.invitees || '[]') : []);
  const label = r.reminder_type === '24h' ? 'en 24 horas' : 'en 30 minutos';
  const content = [
    `**Recordatorio de reunion PM (${label})**`,
    `**${r.title}**`,
    `Fecha: ${fmt(r.scheduled_for)}`,
    `Duracion: ${r.duration_minutes || 30} min`,
    invitees.length ? `Invitados: ${invitees.map(i => i.name).join(', ')}` : null,
    `ID: \`${r.meeting_id}\``
  ].filter(Boolean).join('\n');
  return { json: { ...r, content, idempotency_key: `meeting-reminder:${r.reminder_id}:${r.reminder_type}` } };
});

